/* ---------- realistic curriculum data ---------- */
const pick = arr => arr[Math.floor(Math.random() * arr.length)];
const rint = (a, b) => Math.floor(a + Math.random() * (b - a + 1));

// 20 modules — a realistic DSA → CS-fundamentals track
const MODULE_TITLES = ["Programming Foundations", "Time & Space Complexity", "Arrays & Strings", "Searching & Binary Search", "Sorting Algorithms", "Recursion & Backtracking", "Linked Lists", "Stacks & Queues", "Hashing", "Two Pointers & Sliding Window", "Trees & BST", "Heaps & Priority Queues", "Greedy Algorithms", "Dynamic Programming", "Graphs", "Advanced Graph Algorithms", "Tries & Strings", "Segment Trees & Fenwick", "Object-Oriented Design", "Databases & SQL"];

// class-title fragments, combined per class for variety
const CLASS_POOL = ["Introduction & Setup", "Big-O Notation", "Array Fundamentals", "Prefix & Suffix Sums", "Subarray Problems", "Two Pointers", "Sliding Window", "String Manipulation", "Pattern Matching", "Binary Search Basics", "Search-Space Reduction", "Merge Sort", "Quick Sort", "Counting & Radix Sort", "Recursion Fundamentals", "Backtracking", "Subsets & Permutations", "Linked List Basics", "Fast & Slow Pointers", "Reversing a List", "Stack Applications", "Monotonic Stack", "Queues & Deques", "Hashing Fundamentals", "Hash Maps in Practice", "Collision Handling", "Tree Traversals", "BST Operations", "Balanced Trees", "Heaps & Priority Queues", "Top-K Problems", "Greedy Techniques", "Interval Scheduling", "DP: 1-D Problems", "DP: Grids", "Knapsack Variants", "DP on Subsequences", "Graphs: BFS", "Graphs: DFS", "Dijkstra's Algorithm", "Union–Find", "Topological Sort", "Tries", "Segment Trees", "Bit Manipulation", "System Design Primer", "SQL Joins", "Indexing & Query Plans"];
// class types — combined with the module title for topic-relevant names
const CLASS_KINDS = ["Introduction", "Fundamentals", "Core Patterns", "Implementation", "Worked Examples", "Common Pitfalls", "Practice Problems", "Hard Problems", "Interview Prep", "Optimization Tricks", "Live Problem Solving", "Recap & Quiz"];
const LIVE_VALS = ["100%", "98%", "95%", "92%", "90%", "88%", "85%", "80%"];
const ASSIGN_VALS = ["10/10", "9/10", "8/10", "12/12", "7/8", "6/7", "5/5", "9/9"];
const THIRD_VALS = ["6/6", "8/8", "9/9", "10/10", "3/5", "7/8", "4/6", "5/7"];
const MONTHS = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
const MONTHS_UP = MONTHS.map(m => m.toUpperCase());
const DAYS_IN = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
const dateCursor = {
  m: 6,
  day: 4
}; // running date across all classes (starts ~Jul 4)
function nextDate(step) {
  dateCursor.day += step;
  while (dateCursor.day > DAYS_IN[dateCursor.m]) {
    dateCursor.day -= DAYS_IN[dateCursor.m];
    dateCursor.m = (dateCursor.m + 1) % 12;
  }
  return {
    mon: MONTHS_UP[dateCursor.m],
    day: dateCursor.day
  };
}

/* Generate one module's classes. mode: "done" | "current" | "upcoming".
   For the current module, the class at `activeAt` is the upcoming one. */
function makeClasses(moduleTitle, count, mode) {
  const out = [];
  const activeAt = mode === "current" ? rint(4, Math.max(5, Math.floor(count * 0.55))) : -1;
  for (let j = 0; j < count; j++) {
    const d = nextDate(rint(1, 2));
    const kind = CLASS_KINDS[j % CLASS_KINDS.length];
    const part = j >= CLASS_KINDS.length ? ` (Part ${Math.floor(j / CLASS_KINDS.length) + 1})` : "";
    const done = mode === "done" ? true : mode === "upcoming" ? false : j < activeAt;
    out.push({
      mon: d.mon,
      day: d.day,
      title: `${j + 1}. ${moduleTitle}: ${kind}${part}`,
      live: pick(LIVE_VALS),
      assign: pick(ASSIGN_VALS),
      third: {
        label: j % 4 === 3 ? "Projects" : "Practice",
        val: pick(THIRD_VALS)
      },
      lock: true,
      done,
      active: j === activeAt
    });
  }
  return out;
}

// completed class → green value (no check icon); upcoming/future class → muted "—"
function statValue(l, v) {
  return l.done ? `<span class="stat-col__value">${v}</span>` : `<span class="stat-col__value stat-col__value--todo">—</span>`;
}

// one stat column: category icon by default, full label on row hover
function statCol(icon, label, lesson, value, lock) {
  return `
    <div class="stat-col">
      <span class="stat-col__head">
        <span class="stat-col__icon">${icon}</span>
        <span class="stat-col__label">${label}${lock ? ICON.lock : ""}</span>
      </span>
      ${statValue(lesson, value)}
    </div>`;
}
function lessonRow(l) {
  return `
    <div class="lesson ${l.active ? "lesson--active" : ""}">
      <div class="lesson__date">
        <span class="mon">${l.mon}</span>
        <span class="day">${l.day}</span>
      </div>
      <div class="lesson__title">
        <span class="lesson__name">${l.title}</span>
        ${l.active ? `<span class="lesson__timer"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="13" r="8"/><path d="M12 9v4l2 2"/><path d="M5 3 2 6"/><path d="m22 6-3-3"/></svg>Starts in <span class="lesson__count" data-countdown>25:00</span></span>` : ""}
      </div>
      <div class="lesson__stats">
        ${statCol(ICON.catLive, "Live Class", l, l.live, false)}
        ${statCol(ICON.catAssign, "Assignments", l, l.assign, false)}
        ${statCol(l.third.label === "Projects" ? ICON.catProjects : ICON.catPractice, l.third.label, l, l.third.val, l.lock)}
      </div>
      <span class="lesson__chev">${ICON.chevSm}</span>
    </div>`;
}
